    98→            location_1: 'monetizacao',
    99→            location_2: 'hub_recompensas_spmais',
   100→            location_3: 'saiba_mais',
   101→          });
   102→        },
   103→      } as propsItems;
   104→    });
   105→  }, [selectedCategory]);
   106→
   107→  const hasError =
   108→    !selectedCategory ||
   109→    typeof selectedCategory?.value === 'string' ||
   110→    status === ParameterPointsProgramStatus.ERROR;
   111→
   112→  return {
   113→    data: items,
   114→    title: selectedCategory?.category || '',
   115→    widthWithPaddingInnerLargerWithMargin,
   116→    onNavigation: handleNavigation,
   117→    hasError,
   118→  };
   119→}
   120→
   121→export default function LearnMoreRewardProgram() {
   122→  const {
   123→    data,
   124→    title,
   125→    widthWithPaddingInnerLargerWithMargin,
   126→    onNavigation,
   127→    hasError,
   128→  } = useLearnMoreRewardProgram();
